import json

class CustomObject:
    def __init__(self, value):
        self.value = value

def save_preferences(file_path, preferences):
    with open(file_path, 'w') as file:
        json.dump(preferences, file, default=lambda o: o.__dict__, indent=4)

def load_preferences(file_path):
    with open(file_path, 'r') as file:
        data = json.load(file)
        return _convert_to_objects(data)

def _convert_to_objects(data):
    if isinstance(data, dict):
        return {key: _convert_to_objects(value) for key, value in data.items()}
    elif isinstance(data, list):
        return [_convert_to_objects(item) for item in data]
    elif isinstance(data, CustomObject):
        return CustomObject(data.value)
    else:
        return data